<p>


<p class="wp-block-paragraph">By obtaining a long-term residence permit in Turkey, you are both strengthening your ties with Turkey and taking an important step towards establishing a permanent life here. Now is the time to take action and apply for this permit!</p>', '$.wp_published_at', '2025-08-21T06:10:34Z', '$.wp_modified_at', '2026-03-15T18:45:29Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/06/long-term-residence-permit-in-turkiye-conditions-and-guide.webp","alt":"Person holding documents outside a Turkish building, representing long-term residence permit.","title":"long-term-residence-permit-in-turkiye-conditions-and-guide"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'long-term-residence-permit' );
